
package com.example.taxgap.domain.entity; import com.example.taxgap.domain.enums.Severity; import jakarta.persistence.*; import java.time.*;
@Entity @Table(name="tax_rules")
public class TaxRule { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(unique=true, nullable=false) private String name; @Column(nullable=false) private String type; private String description; private boolean enabled=true; @Enumerated(EnumType.STRING) private Severity severity; @Column(name="config_json", columnDefinition="JSON") private String configJson; private LocalDateTime updatedAt;
 public Long getId(){return id;} public void setId(Long v){id=v;} public String getName(){return name;} public void setName(String v){name=v;} public String getType(){return type;} public void setType(String v){type=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public boolean isEnabled(){return enabled;} public void setEnabled(boolean v){enabled=v;} public Severity getSeverity(){return severity;} public void setSeverity(Severity v){severity=v;} public String getConfigJson(){return configJson;} public void setConfigJson(String v){configJson=v;} public LocalDateTime getUpdatedAt(){return updatedAt;} public void setUpdatedAt(LocalDateTime v){updatedAt=v;} }
